// ============================================================
// BUILD CATEGORY SECTION
// ============================================================
function buildCategoryGrids() {
    const grid = document.getElementById('categoryGrid');
    if (!grid) return;
    grid.innerHTML = categories.map(c => `
        <div class="cat-card" onclick="filterProducts('${c.id}'); document.getElementById('products').scrollIntoView({behavior:'smooth'})">
            <div class="cat-icon" style="background:${c.color};color:${c.iconColor}">
                <span style="font-size:2rem">${c.icon}</span>
            </div>
            <h3>${c.label}</h3>
            <p style="font-size:.75rem;color:#64748b;margin-top:4px">${c.sub.slice(0,3).join(' · ')}</p>
            <span class="cat-count">${products.filter(p=>p.cat===c.id).length}+ Products</span>
        </div>
    `).join('');
}

function buildNavCategories() {
    const navList = document.getElementById('navCatList');
    if (!navList) return;
    navList.innerHTML = categories.map(c => `
        <li><a href="#products" onclick="filterProducts('${c.id}')">${c.label}</a></li>
    `).join('');
}

function buildMegaMenu() {
    const mega = document.getElementById('megaMenuCats');
    if (!mega) return;
    
    const columns = 4;
    const itemsPerCol = Math.ceil(categories.length / columns);
    const cols = [];
    for (let i = 0; i < categories.length; i += itemsPerCol) {
        cols.push(categories.slice(i, i + itemsPerCol));
    }
    
    mega.innerHTML = cols.map(col => `
        <div class="mega-col">
            ${col.map(c => `
                <div class="mega-cat-group">
                    <div class="mega-cat-header" onclick="filterProducts('${c.id}'); closeMega(); document.getElementById('products').scrollIntoView({behavior:'smooth'})">
                        <span style="font-size:1.1rem">${c.icon}</span>
                        <strong>${c.label}</strong>
                    </div>
                    <ul class="mega-cat-links">
                        ${c.sub.map(s => `
                            <li><a href="#products" onclick="filterProducts('${c.id}'); closeMega(); document.getElementById('products').scrollIntoView({behavior:'smooth'})">${s}</a></li>
                        `).join('')}
                    </ul>
                </div>
            `).join('')}
        </div>
    `).join('');
    
    console.log('Mega menu built with', categories.length, 'categories');
}

// ============================================================
// RENDER PRODUCTS
// ============================================================

// ============================================================
// PRODUCT RENDERING
// ============================================================
function renderProducts(categoryId = 'all') {
    const grid = document.getElementById('productsGrid');
    if (!grid) return;
    
    let filtered = products;
    if (categoryId !== 'all') {
        filtered = products.filter(p => p.cat === categoryId);
    }
    
    const searchTerm = document.getElementById('searchInput');
    if (searchTerm && searchTerm.value.trim() !== '') {
        const q = searchTerm.value.toLowerCase();
        filtered = filtered.filter(p => 
            p.name.toLowerCase().includes(q) || 
            p.desc.toLowerCase().includes(q)
        );
    }
    
    // Sort logic
    const sort = document.getElementById('sortSelect');
    if (sort && sort.value) {
        if (sort.value === 'low') filtered.sort((a,b) => a.price - b.price);
        if (sort.value === 'high') filtered.sort((a,b) => b.price - a.price);
        if (sort.value === 'new') filtered.sort((a,b) => b.id - a.id);
    }

    if (filtered.length === 0) {
        grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:50px;color:var(--text-muted)">No products found matching your criteria.</div>';
        document.getElementById('productCount').textContent = '(0 items)';
        return;
    }

    document.getElementById('productCount').textContent = `(${filtered.length} items)`;
    
    // pagination (just show first 100 max to avoid lag for 4000 items)
    const maxItems = 100;
    const displayItems = filtered.slice(0, maxItems);
    
    grid.innerHTML = displayItems.map(productCardHTML).join('');
    
    if(filtered.length > maxItems) {
        grid.innerHTML += `<div style="grid-column:1/-1;text-align:center;padding:20px;color:var(--text-muted)">Showing top ${maxItems} results. Use search or filters to narrow down.</div>`;
    }
}



function renderAllProductSections() {
    const container = document.getElementById('dynamicCategorySections');
    if (!container) return;
    
    let html = '';
    
    // For each category, get the top 4 products
    categories.forEach(cat => {
        // filter products by this category
        const catProducts = products.filter(p => p.cat === cat.id);
        
        // Skip rendering a section if there are no products
        if (catProducts.length === 0) return;
        
        // Take top 4 (you could sort by rating or price here if needed)
        const topProducts = catProducts.slice(0, 4);
        
        // Alternate background colors for visual separation
        const bgClass = html.includes('bg-white') && !html.includes('style="background:#f1f5f9"') ? 'style="background:#f1f5f9"' : 'class="bg-white"';
        
        html += `
        <section class="section-pad ${bgClass.includes('class') ? 'bg-white' : ''}" ${bgClass.includes('style') ? bgClass : ''} id="sec-${cat.id}">
            <div class="container">
                <div class="section-header">
                    <div>
                        <h2 class="section-title" style="text-align:left;margin-bottom:5px">${cat.label}</h2>
                        <p class="section-sub">Top selling products in ${cat.label}</p>
                    </div>
                    <button class="btn btn-outline-sm" onclick="filterProducts('${cat.id}');document.getElementById('products').scrollIntoView({behavior:'smooth'})">View All →</button>
                </div>
                <div class="product-grid mini-grid">
                    ${topProducts.map(productCardHTML).join('')}
                </div>
            </div>
        </section>`;
    });
    
    container.innerHTML = html;
}

function filterProducts(cat) {
    document.querySelectorAll('.filter-tag').forEach(t => t.classList.remove('active'));
    const active = Array.from(document.querySelectorAll('.filter-tag'))
        .find(t => t.dataset.cat === cat || (cat === 'all' && t.dataset.cat === 'all'));
    if (active) active.classList.add('active');

    renderProducts(cat);
}

// Consolidated product card generator
// (Used by renderProducts and renderAllProductSections)
function productCardHTML(p) {
    const priceStr = p.price > 0 ? '₹' + p.price.toLocaleString('en-IN') : 'Price on Request';
    const mrpStr = p.price > 0 ? '₹' + (p.price * 1.2).toLocaleString('en-IN') : '';
    const discount = p.price > 0 ? 20 : 0; 
    const badgeHTML = p.badge && p.badge !== 'null' ? `<span class="product-badge badge-${p.badge}">${p.badge.toUpperCase()}</span>` : '';
    const catObj = categories.find(c => c.id === p.cat);
    const catLabel = catObj ? catObj.label : p.cat;
    
    // Improved image path logic: Use live site as primary source for relative paths
    let imgUrl = p.img;
    if (imgUrl && imgUrl.startsWith('/')) {
        imgUrl = 'https://ahujasalesindia.com' + imgUrl;
    } else if (!imgUrl) {
        imgUrl = 'https://ahujasalesindia.com/images/logo.png';
    }
    
    return `
    <div class="product-card">
        ${badgeHTML}
        <div class="product-img">
            <img src="${imgUrl}" alt="${p.name}" loading="lazy" 
                 onerror="this.onerror=null; this.src='https://ahujasalesindia.com/images/logo.png'; this.style.objectFit='contain'; this.parentElement.classList.add('img-failed');"
                 style="width:100%;height:100%;object-fit:contain;padding:15px">
            <div class="product-img-overlay">
                <button onclick="openBuyNow(${p.id})"><i class="fas fa-bolt"></i> Buy Now</button>
                <button onclick="addToCart(${p.id})"><i class="fas fa-cart-plus"></i> Cart</button>
            </div>
            <div class="img-fallback" style="display:none">🔧</div>
        </div>
        <div class="product-body">
            <div class="product-cat" style="display:flex; justify-content:space-between; align-items:center;">
                <span>${catLabel}</span>
                ${p.inStock ? '<span class="in-stock">● In Stock</span>' : '<span style="color:#ef4444;font-size:0.72rem;font-weight:700">Out of Stock</span>'}
            </div>
            <h3 class="product-name" title="${p.name}">${p.name.length > 50 ? p.name.substring(0, 50) + '...' : p.name}</h3>
            <p class="product-desc" title="${p.desc}">${p.desc.substring(0, 80)}${p.desc.length > 80 ? '...' : ''}</p>
            <div class="product-rating">
                <span class="stars">★★★★★</span>
                <span class="rating-count">(${p.reviews} reviews)</span>
            </div>
            <div class="product-price-row">
                <span class="product-price">${priceStr}</span>
                ${p.price > 0 ? `<span class="product-mrp">${mrpStr}</span>` : ''}
                ${discount > 0 ? `<span class="product-discount">${discount}% off</span>` : ''}
            </div>
            <div class="product-actions">
                <button class="btn btn-outline" onclick="addToCart(${p.id})">
                    <i class="fas fa-cart-plus"></i> Add to Cart
                </button>
                <button class="btn btn-primary" onclick="openBuyNow(${p.id})">
                    <i class="fas fa-bolt"></i> Buy Now
                </button>
            </div>
        </div>
    </div>`;
}

// ============================================================
// CART LOGIC
// ============================================================
function addToCart(productId) {
    const product = products.find(p => p.id === productId);
    if (!product) return;
    const existing = cart.find(i => i.id === productId);
    if (existing) { existing.qty += 1; }
    else { cart.push({ id: productId, name: product.name, cat: product.cat, img: product.img, price: product.price, qty: 1 }); }
    saveCart(); updateCartUI(); renderCartItems();
    showToast(`Added: ${product.name.substring(0, 40)}...`);
}

function removeFromCart(productId) {
    cart = cart.filter(i => i.id !== productId);
    saveCart(); updateCartUI(); renderCartItems();
}

function updateCartQty(productId, delta) {
    const item = cart.find(i => i.id === productId);
    if (!item) return;
    item.qty = Math.max(1, item.qty + delta);
    saveCart(); updateCartUI(); renderCartItems();
}

function setCartQty(productId, val) {
    const item = cart.find(i => i.id === productId);
    if (!item) return;
    item.qty = Math.max(1, parseInt(val) || 1);
    saveCart(); updateCartUI();
}

function saveCart() { localStorage.setItem('ahuja_cart', JSON.stringify(cart)); }

function updateCartUI() {
    const total = cart.reduce((s, i) => s + i.price * i.qty, 0);
    const count = cart.reduce((s, i) => s + i.qty, 0);
    document.getElementById('cartCount').textContent = count;
    document.getElementById('cartItemCountBadge').textContent = count;
    document.getElementById('cartTotal').textContent = `₹${total.toLocaleString('en-IN', { minimumFractionDigits: 2 })}`;
    const f = document.getElementById('cartFooter');
    if (f) f.style.display = cart.length ? 'flex' : 'none';
}

function renderCartItems() {
    const container = document.getElementById('cartItems');
    if (cart.length === 0) {
        container.innerHTML = `<div class="cart-empty"><i class="fas fa-shopping-bag"></i><p>Your cart is empty</p></div>`;
        return;
    }
    container.innerHTML = cart.map(item => `
        <div class="cart-item">
            <div class="cart-item-icon">
                <img src="${item.img}" alt="${item.name}" style="width:100%;height:100%;object-fit:contain;padding:4px"
                     onerror="this.style.display='none'">
            </div>
            <div class="cart-item-info">
                <div class="cart-item-name">${item.name}</div>
                <div class="cart-item-cat">${categories.find(c=>c.id===item.cat)?.label || item.cat}</div>
                <div class="cart-item-qty-row">
                    <div class="qty-ctrl">
                        <button onclick="updateCartQty(${item.id},-1)">−</button>
                        <input type="number" value="${item.qty}" min="1" onchange="setCartQty(${item.id},this.value)">
                        <button onclick="updateCartQty(${item.id},1)">+</button>
                    </div>
                    <span class="cart-item-price">${item.price > 0 ? '₹' + (item.price * item.qty).toLocaleString('en-IN') : 'Price on Request'}</span>
                </div>
            </div>
            <button class="cart-item-remove" onclick="removeFromCart(${item.id})"><i class="fas fa-trash-alt"></i></button>
        </div>`).join('');
}

// ============================================================
// CART SIDEBAR
// ============================================================
function openCart() {
    renderCartItems(); updateCartUI();
    document.getElementById('cartSidebar').classList.add('open');
    document.getElementById('cartOverlay').classList.add('active');
    document.body.style.overflow = 'hidden';
}
function closeCart() {
    document.getElementById('cartSidebar').classList.remove('open');
    document.getElementById('cartOverlay').classList.remove('active');
    document.body.style.overflow = '';
}

function checkout() {
    if (cart.length === 0) { showToast('Cart is empty!', 'error'); return; }
    closeCart();
    openCustomerDetails('checkout');
}

// ============================================================
// BUY NOW MODAL
// ============================================================
function openBuyNow(productId) {
    const p = products.find(x => x.id === productId);
    if (!p) return;
    currentBuyProduct = p;
    document.getElementById('modalProductName').textContent = p.name;
    document.getElementById('modalProductPrice').textContent = p.price > 0
        ? `₹${p.price.toLocaleString('en-IN')}`
        : 'Price on Request';
    document.getElementById('modalQty').value = 1;
    const imgEl = document.getElementById('modalProductImg');
    if (imgEl) { imgEl.src = p.img; imgEl.alt = p.name; }
    
    renderRelatedProducts(p);
    document.getElementById('modalOverlay').classList.add('active');
    document.body.style.overflow = 'hidden';
}
function closeModal() {
    document.getElementById('modalOverlay').classList.remove('active');
    document.body.style.overflow = '';
    currentBuyProduct = null;
}
function changeModalQty(delta) {
    const inp = document.getElementById('modalQty');
    inp.value = Math.max(1, parseInt(inp.value || 1) + delta);
}
function confirmBuyNow() {
    if (!currentBuyProduct) return;
    closeModal();
    openCustomerDetails('buynow');
}
function addModalItemToCart() {
    if (!currentBuyProduct) return;
    addToCart(currentBuyProduct.id);
    closeModal(); openCart();
}
function closeOrderModal() {
    document.getElementById('orderModalOverlay').classList.remove('active');
    document.body.style.overflow = '';
}

// ============================================================
// MEGA MENU
// ============================================================
function setupAllCatsBtn() {
    const btn = document.getElementById('allCatsBtn');
    const menu = document.getElementById('megaMenu');
    if (!btn || !menu) return;
    btn.addEventListener('click', e => {
        e.stopPropagation();
        menu.classList.toggle('open');
    });
    document.addEventListener('click', () => menu.classList.remove('open'));
    menu.addEventListener('click', e => e.stopPropagation());
}
function closeMega() {
    document.getElementById('megaMenu')?.classList.remove('open');
}

// ============================================================
// SEARCH
// ============================================================
function handleSearch(e) { if (e.key === 'Enter') performSearch(); }
function performSearch() {
    const query = document.getElementById('searchInput').value.trim();
    const cat = document.getElementById('searchCat').value || 'all';
    
    // Set the filter tag active if search is for a cat
    filterProductsUpdateTags(cat);
    
    // renderProducts already handles reading #searchInput and #searchCat-style filters
    renderProducts(cat);
    
    document.getElementById('products').scrollIntoView({ behavior: 'smooth' });
}
function filterProductsUpdateTags(cat) {
    document.querySelectorAll('.filter-tag').forEach(t => t.classList.remove('active'));
    const a = document.querySelector(`.filter-tag[data-cat="${cat}"]`);
    if (a) a.classList.add('active');
}

